import re

with open('curriculum/l2-uk-en/bio/petro-sahaidachny.md', 'r', encoding='utf-8') as f:
    text = f.read()

# 1. Expand 'Життєпис: I — Становлення та Морські походи' (Кафа)
kafa_anchor = "Взяття Кафи також завдало нищівного економічного удару по системі работоргівлі, яка живила кримську економіку."
kafa_addition = """ Взяття Кафи також завдало нищівного економічного удару по системі работоргівлі, яка живила кримську економіку. Ця перемога мала неперевершений психологічний ефект. Згідно з тогочасними хроніками, захоплення Кафи вважалося неможливим через її потужні фортифікаційні споруди. Козаки звільнили бранців, а також захопили величезну кількість зброї, золота та коштовностей, які пізніше були використані для фінансування українських шкіл та церков. Ця подія підірвала економіку Кримського ханства та продемонструвала всій Європі, що українське козацтво є силою, здатною успішно протистояти найбільшій імперії свого часу.

> [!quote] Сучасник про взяття Кафи
> "Сагайдачний, як справжній лев, увірвався до лігва ворога, звільняючи тисячі християнських душ від неминучої загибелі, чим здобув собі вічну славу." — невідомий автор XVII століття."""
text = text.replace(kafa_anchor, kafa_addition)

# 2. Expand 'Життєпис: II — Московський похід та Відновлення Церкви' (Московський похід + Церква)
moscow_anchor = "Він знищив московські резерви, розбив ополчення Пожарського і з'єднався з військами Владислава безпосередньо під стінами Москви, врятувавши польську армію від неминучого розгрому."
moscow_addition = """Він знищив московські резерви, розбив ополчення Пожарського і з'єднався з військами Владислава безпосередньо під стінами Москви, врятувавши польську армію від неминучого розгрому. Рухаючись вглиб московських територій, Сагайдачний захопив понад двадцять міст і фортець, серед яких були Лівни, Єлець, Лебедянь та Данков. Його військо продемонструвало виняткову дисципліну та організацію, уникаючи непотрібних втрат і максимально ефективно використовуючи фактор раптовості. Під час облоги Москви козаки штурмували Арбатські та Тверські ворота. Хоча місто не було взято через політичні домовленості, сам факт того, що українське військо стояло під мурами Кремля, став потужним символом могутності Сагайдачного. Це був момент тріумфу, який довів, що козацтво є непереможною силою на континенті, здатною вирішувати долю цілих імперій."""
text = text.replace(moscow_anchor, moscow_addition)

church_anchor = "Відновлення ієрархії легітимізувало православну церкву, повернуло їй канонічний статус і дало українцям потужний інституційний центр опору. Без цього кроку Сагайдачного культурна асиміляція українців була б лише питанням часу."
church_addition = """Відновлення ієрархії легітимізувало православну церкву, повернуло їй канонічний статус і дало українцям потужний інституційний центр опору. Без цього кроку Сагайдачного культурна асиміляція українців була б лише питанням часу. Сам процес відновлення ієрархії був ретельно спланованою таємною операцією. Сагайдачний використав дипломатичну недоторканність Єрусалимського патріарха, щоб обійти заборони польського короля. Козацькі полки, розквартировані навколо Києва, створювали постійну загрозу збройного повстання у разі спроби урядових військ заарештувати патріарха або нововисвячених єпископів. Цей безпрецедентний крок продемонстрував, що козацтво стало повноцінним гарантом релігійних свобод українського народу. Більше того, цей акт забезпечив православній церкві канонічну спадкоємність, без якої вона була б приречена на маргіналізацію та поступове зникнення.

> [!source] Документальне свідчення
> Згідно з тогочасними листами, Сагайдачний особисто гарантував патріарху Феофану повну безпеку: "Ми, Військо Запорозьке, власною кров'ю і життям своїм заприсяглися боронити Вашу Святість і нашу праотцівську віру від будь-яких посягань." """
text = text.replace(church_anchor, church_addition)

# 3. Expand 'Життєпис: III — Хотинська епопея та Смерть'
khotyn_anchor = "Козаки прийняли на себе найважчі удари султанської армії, ставши нездоланним муром, об який розбилися мрії Османа II про європейське панування."
khotyn_addition = """Козаки прийняли на себе найважчі удари султанської армії, ставши нездоланним муром, об який розбилися мрії Османа II про європейське панування. Османська армія мала у своєму складі найкращих воїнів того часу, включаючи елітні підрозділи яничарів, а також потужну артилерію та бойових слонів. Султан Осман II був настільки впевнений у своїй перемозі, що заздалегідь планував маршрут свого тріумфального маршу європейськими столицями. Проте зіткнення з козацькою піхотою, яка вела нищівний вогонь з-за возів, стало для турків справжньою катастрофою. Козаки витримали понад десять масованих штурмів, а також постійно контратакували, завдаючи ворогу колосальних втрат у живій силі. Участь 40-тисячного українського війська змінила баланс сил і врятувала Річ Посполиту від неминучого розгрому.

> [!analysis] Стратегічна ціна перемоги
> Хотинська битва стала тріумфом українського військового генія, але водночас забрала життя найвидатнішого полководця свого часу. Сагайдачний віддав своє життя заради порятунку Європи, продемонструвавши найвищий рівень самопожертви та державної відповідальності."""
text = text.replace(khotyn_anchor, khotyn_addition)


# 4. Expand 'Історичний контекст'
context_anchor = "Європейська криза дозволила йому диктувати умови королю, оскільки без козацького війська Річ Посполита не змогла б вижити у війні на кілька фронтів."
context_addition = """Європейська криза дозволила йому диктувати умови королю, оскільки без козацького війська Річ Посполита не змогла б вижити у війні на кілька фронтів. Тридцятилітня війна вимагала величезних людських та матеріальних ресурсів. У цих умовах українські козаки, як одна з найбоєздатніших армій Європи, стали надзвичайно затребуваними на ринку військових найманців. Хоча офіційно Сагайдачний не брав участі в європейських кампаніях, козацькі загони пізніше активно долучалися до бойових дій на різних театрах Тридцятилітньої війни, здобуваючи безцінний досвід сучасної війни. Це дозволило українцям інтегруватися в загальноєвропейський військово-політичний простір, обмінюватися тактичними інноваціями та зміцнювати свій авторитет серед монархів Європи. Водночас це створило передумови для формування потужної національної армії, яка згодом стане ядром козацької держави під проводом Богдана Хмельницького.

> [!context] Глобальний вимір
> Українське козацтво початку XVII століття було не локальним явищем, а інтегральною частиною європейської військової машини. Вони були обізнані з новітніми європейськими тактиками і водночас привносили власні унікальні інновації, які переймали інші армії."""
text = text.replace(context_anchor, context_addition)


# 5. Expand 'Внесок та Спадщина'
legacy_anchor = "Його інноваційна піхотна тактика, особливо використання рухомого табору (табору з возів), на десятиліття випередила європейську військову думку."
legacy_addition = """Його інноваційна піхотна тактика, особливо використання рухомого табору (табору з возів), на десятиліття випередила європейську військову думку. Ці реформи мали далекосяжні наслідки. Козацьке військо перетворилося на елітну структуру, здатну виконувати складні стратегічні завдання державного рівня. Сагайдачний створив систему військової підготовки, яка передавалася з покоління в покоління. Навіть після його смерті закладені ним принципи організації, дисципліни та тактичної гнучкості залишалися основою козацької військової машини. Завдяки цим перетворенням українське військо здобуло репутацію однієї з найефективніших піхотних армій на континенті, яка могла на рівних протистояти як важкій кавалерії європейського типу, так і мобільній легкій кінноті азійського зразка.

> [!legacy] Спадкоємність поколінь
> Багато полководців, які пізніше стали ключовими фігурами Національно-визвольної війни 1648–1657 років, пройшли військову школу саме під керівництвом Сагайдачного. Його стратегічний геній заклав фундамент для майбутніх перемог Хмельницького під Жовтими Водами, Корсунем та Пилявцями."""
text = text.replace(legacy_anchor, legacy_addition)

with open('curriculum/l2-uk-en/bio/petro-sahaidachny.md', 'w', encoding='utf-8') as f:
    f.write(text)

